INSERT INTO film(id_film, nom_film, synopsis, genre, date_sortie, affiche)
VALUES
(1, "Titanic", "Le film se déroule en avril 1912, lors du voyage inaugural du Titanic, le paquebot le plus grand et le plus moderne de son époque, réputé pour son insubmersibilité. L'histoire suit deux jeunes passagers de milieux sociaux opposés : Jack Dawson, un artiste pauvre, et Rose DeWitt Bukater, une aristocrate promise à un homme qu'elle n'aime pas, Caledon Hockley.", 'Romance', 1998, 'https://image.tmdb.org/t/p/w500/9xjZS2rlVxm8SFx8kPC3aIGCOYQ.jpg'),
(2, "La La Land", "Un embouteillage monstre s'est formé sur un autopont de Los Angeles (Another Day of Sun). Mia Dolan (Emma Stone), une actrice débutante, répète un dialogue de film dans sa voiture. Lorsque Sebastian Wilder (Ryan Gosling) klaxonne derrière elle, elle lui répond par un doigt d'honneur.", 'Romance', 2017, 'https://image.tmdb.org/t/p/w500/uDO8zWDhfWwoFdKS4fzkUJt0Rf0.jpg'),
(3, "Eternal sunshine of the spotless mind", "Joel et Clementine ne voient plus que les mauvais côtés de leur tumultueuse histoire d'amour, au point que celle-ci fait effacer de sa mémoire toute trace de cette relation. Effondré, Joel contacte l'inventeur du procédé Lacuna, le Dr.", 'Romance', 2004, 'https://image.tmdb.org/t/p/w500/5MwkWH9tYHv3mV9OdYTMR5qreIz.jpg'),
(4, 'Call Me By Your Name', "Été 1983. Elio Perlman, 17 ans, passe ses vacances dans la villa du XVIIe siècle que possède sa famille en Italie, à jouer de la musique classique, à lire et à flirter avec son amie Marzia. Son père, éminent professeur spécialiste de la culture gréco-romaine, et sa mère, traductrice, lui ont donné une excellente éducation, et il est proche de ses parents.", 'Romance', 2017, 'https://image.tmdb.org/t/p/w500/mZ4gBdfkhP9tvLH1DO4m4HYtiyi.jpg'),
(5, "Le Destin d'Amélie Poulain", "Amélie, une jeune serveuse dans un bar de Montmartre, passe son temps à observer les gens et à laisser son imagination divaguer. Elle s'est fixé un but : faire le bien de ceux qui l'entourent.", 'Romance', 2001, 'https://image.tmdb.org/t/p/w500/nSxDa3M9aMvGVLoItzWTepQ5h5d.jpg'),
(6, 'Nos étoiles contraires', "Depuis son enfance, Hazel a des problèmes respiratoires, l'obligeant à porter un tube à oxygène en permanence. Sur les conseils de sa mère, elle participe à un groupe de soutien, où elle fait la connaissance d'Augustus, qui a perdu une jambe à cause d'un cancer. Charismatique et sûr de lui, le jeune homme devient rapidement proche d'Hazel, lui montrant le bon côté des choses. Il arrive même à retrouver l'écrivain préféré de sa nouvelle amie, et planifie un voyage à Amsterdam pour le rencontrer.", 'Romance', 2014, 'https://image.tmdb.org/t/p/w500/kcVuktIlrn9SAN1uBmPDnocTQmF.jpg'),
(7, 'Princess Bride', "Princess Bride est une comédie romantique d'aventure et de fantasy où un grand-père raconte à son petit-fils malade l'histoire de Bouton d'or et de Westley, un récit mêlant amour, humour, duels et péripéties dans un royaume imaginaire...", 'Romance', 1988, 'https://image.tmdb.org/t/p/w500/2FC9L9MrjBoGHYjYZjdWQdopVYb.jpg'),
(8, "Roméo + Juliette", "Roméo + Juliette transpose la tragédie de Shakespeare dans un univers urbain moderne et stylisé, où deux jeunes issus de familles rivales tombent éperdument amoureux.", 'Romance', 1997, 'https://image.tmdb.org/t/p/w500/nAfCa387dsgB0IwjwOEJcQOc32f.jpg'),
(9, 'People we meet on Vacation', "People We Meet on Vacation suit Poppy, spontanée et globe-trotteuse, et Alex, calme et casanier, amis opposés qui se retrouvent chaque été pour voyager. Après des années de silence, un dernier périple ravive souvenirs, émotions et sentiments inavoués...", 'Romance', 2026, 'https://image.tmdb.org/t/p/w500/peG6482ALJQ9Tbvv2P38BquVk0f.jpg'),
(10, 'Orgeuil et Préjugés', "Dans l'Angleterre georgienne, la vive Elizabeth Bennet et le réservé Mr Darcy se heurtent d'abord par malentendu avant de voir grandir leur estime mutuelle. Porté par Keira Knightley et Matthew Macfadyen, ce film séduit par ses décors somptueux, ses costumes soignés et la chimie entre les acteurs.", 'Romance', 2005, 'https://image.tmdb.org/t/p/w500/placeholder.jpg'),
(11, 'Une bouteille à la mer', "Une bouteille à la mer met en scène Theresa, journaliste à Chicago, qui, fragilisée par un divorce, découvre sur une plage une émouvante lettre d'amour scellée dans une bouteille. Intriguée, elle part à la recherche de son auteur, un constructeur de bateaux meurtri par la perte de son épouse.", 'Romance', 1999, 'https://image.tmdb.org/t/p/w500/9W12xfX5rHUhF8kvr1kciDOyjA3.jpg'),
(12, "A tous les garçons que j'ai aimé", "La vie sentimentale de Lara Jean Song Covey passe du rêve à la pire des réalités quand ses lettres d'amour, adressées aux cinq garçons qu'elle a toujours aimés, arrivent mystérieusement chez leurs destinataires.", 'Romance', 2018, 'https://image.tmdb.org/t/p/w500/placeholder.jpg'),
(13, "Charlie St.Cloud", "Le Secret de Charlie raconte l'histoire de Charlie, un jeune homme marqué par la perte tragique de son frère, à qui il est lié par une promesse quotidienne. Devenu gardien de cimetière, il mène une vie figée dans le passé jusqu'à ce qu'une rencontre inattendue bouleverse ses repères et l'oblige à choisir entre honorer le souvenir ou saisir une seconde chance...", 'Romance', 2010, 'https://image.tmdb.org/t/p/w500/r4XSrs6N086EU8CNm339dHRPhZg.jpg'),
(14, "L'Amour Ouf", "L'Amour ouf de Gilles Lellouche raconte, dans le nord des années 80, la passion intense et contrariée entre Jackie, lycéenne appliquée, et Clotaire, jeune rebelle issu d'un milieu ouvrier...", 'Romance', 2024, 'https://image.tmdb.org/t/p/w500/yu9dRyKcUHTfKcqsomUtpord4t3.jpg'),
(15, 'Dirty Dancing', "Dans les années soixante, Bébé passe des vacances familiales ennuyeuses jusqu'au jour où elle apprend que des animateurs du village estival forment une troupe de danse. Pour cette jeune fille sage, c'est le début de l'émancipation à travers l'apprentissage du dirty dancing, une danse très sensuelle. Elle fait la connaissance de Johnny Castel, un professeur de danse qui va bouleverser son existence...", 'Romance', 1987, 'https://image.tmdb.org/t/p/w500/9Jw6jys7q9gjzVX5zm1z0gC8gY9.jpg'),
(16, 'Obsession', "Après avoir invoqué la magie d'un ancien artefact pour conquérir la fille qu'il aime en secret, un adolescent voit son souhait se réaliser au-delà de ses espérances. Mais l'affection tant désirée se mue en obsession incontrôlable...", 'Horreur', 2026, 'https://image.tmdb.org/t/p/w500/bRwnj8WEKBCvmfeUNOukJPwB43K.jpg'),
(17, 'ÇA', 'Le film se déroule dans la ville de Derry, dans le Maine, où une entité métamorphe, connue sous le nom de "Ça", émerge des égouts tous les 27 ans pour se nourrir des peurs des enfants. Un groupe de sept adolescents, surnommé le "Club des Ratés", se regroupe pour affronter cette créature qui terrorise leur ville. Chaque membre du groupe a ses propres peurs et traumatismes, mais ensemble, ils décident de surmonter leurs angoisses pour combattre "Ça"', 'Horreur', 2017, 'https://image.tmdb.org/t/p/w500/s5wWOehpQcktKPXHJsqgDqBubvJ.jpg'),
(18, 'Alien', "En 2122, le cargo spatial Nostromo, de retour vers la Terre avec son chargement de minerai, capte un signal radio émis depuis un planétoïde isolé. L'ordinateur de bord du vaisseau — appelé « Maman » — interrompt alors le trajet du Nostromo et réveille l'équipage maintenu en biostase (sommeil artificiel).", 'Horreur', 1979, 'https://image.tmdb.org/t/p/w500/vfrQk5IPloGg1v9Rzbh2Eg3VGyM.jpg'),
(19, 'Simetierre', "Louis Creed, sa femme Rachel, ses enfants Ellie et Gage, et Church le chat, quittent Boston pour s'installer à Ludlow, dans le Maine, dans une maison forestière isolée, à la périphérie de la ville. En se promenant dans la forêt, Ellie fait la découverte d'un cimetière pour animaux...", 'Horreur', 2019, 'https://image.tmdb.org/t/p/w500/a1gIACZb04bL8EvLqMpofW2Eqeo.jpg'),
(20, 'Destination Finale', "Alex Browning s'apprête à partir pour Paris dans le cadre d'un voyage d'études. Alors que son avion est sur le point de décoller, il voit soudain l'appareil exploser en vol. Terrifié, il tente d'alerter les autres passagers et se retrouve finalement expulsé de l'avion en compagnie de Tod, son meilleur ami, de Clear, Carter, Terry, Billy, et de leur professeur Valerie Lewton.", 'Horreur', 2000, 'https://image.tmdb.org/t/p/w500/dMJzPWyyjqsEfCA7tVIprvECyvb.jpg'),
(21, 'Backrooms', "Une psychothérapeute est contraint d'affronter l'inconnu dans le but de retrouver un patient vivant, ayant disparu dans une mystérieuse dimension qui dépasse la réalité.", 'Horreur', 2026, 'https://image.tmdb.org/t/p/w500/rhGx6E3qRNMgj3i5su2oukNHwIQ.jpg'),
(22, 'The Shining', "Le film met en scène Jack Torrance, un écrivain ex-alcoolique et en panne d'inspiration, engagé pendant tout l'hiver comme gardien d'un grand hôtel isolé du Colorado, l'Hôtel Overlook, où il espère surmonter enfin son manque d'inspiration littéraire. Il s'y installe avec son épouse Wendy et leur jeune fils Danny, lequel possède un don surnaturel de voyance. Alors que les semaines passent, Jack piétine dans l'écriture de son livre. Son fils Danny est lui-même de plus en plus hanté par des visions terrifiantes de meurtres qui se sont déroulés à l'hôtel il y a de cela des décennies.", 'Horreur', 1980, 'https://image.tmdb.org/t/p/w500/uAR0AWqhQL1hQa69UDEbb2rE5Wx.jpg'),
(23, 'Pearl', "En 1918, Pearl est une jeune fille issue d'une famille d'immigrés allemands, vivant dans une ferme au Texas, pendant que Howard, son mari, sert l'armée américaine dans la Première guerre mondiale. Le père de Pearl est infirme et paralysé et Ruth, sa mère, stricte, insiste pour qu'elle s'occupe de la ferme et de son père, la famille étant isolée pour se protéger de la grippe espagnole. Pearl veut devenir danseuse et star de cinéma, ce que sa mère désapprouve..", 'Horreur', 2022, 'https://image.tmdb.org/t/p/w500/z5uIG81pXyHKg7cUFIu84Wjn4NS.jpg'),
(24, 'Wedding Nightmare', "Wedding Nightmare est une comédie horrifique où la nuit de noces d'une jeune mariée bascule lorsqu'elle doit participer à une tradition familiale meurtrière orchestrée par sa riche et excentrique belle-famille...", 'Horreur', 2019, 'https://image.tmdb.org/t/p/w500/9vX0bdzMXCuEQys1GarBSYqTXcX.jpg'),
(25, 'The Conjuring', "Conjuring : Les Dossiers Warren suit Ed et Lorraine Warren, enquêteurs spécialisés dans le paranormal, appelés pour aider une famille confrontée à une présence maléfique dans leur ferme isolée..", 'Horreur', 2013, 'https://image.tmdb.org/t/p/w500/wVYREutTvI2tmxr6ujrHT704wGF.jpg'),
(26, "Five Nights at Freddy's", "Un veilleur de nuit surveille une pizzeria un peu spéciale. Si la journée, elle est environnée par de gentilles peluches en animatroniques faisant le bonheur des enfants, celles-ci se transforment la nuit en créatures meurtrières. Immobile dans une pièce, il faut surveiller leurs allées et venues via les caméras et fermer les portes lorsqu'ils s'approchent en faisant attention aux réserves d'électricité limitées. Le but est alors de survivre pendant cinq nuits.", 'Horreur', 2023, 'https://image.tmdb.org/t/p/w500/udAxQEORq2I5wxI97N2TEqdhzBE.jpg'),
(27, 'Dernier train pour Busan', "Seok-woo, jeune homme d'affaires débordé, accepte de ramener sa fille Soo-an chez sa mère, dont il est séparé, à Busan. Ils embarquent dans un train, sans se douter que la ville qu'ils s'apprêtent à quitter vient d'être contaminée par un dangereux virus transformant la population en morts-vivants. Le train finit par quitter la gare, mais une femme contaminée est parvenue à grimper à bord. Elle menace à présent l'ensemble des voyageurs.", 'Horreur', 2016, 'https://image.tmdb.org/t/p/w500/vNVFt6dtcqnI7hqa6LFBUibuFiw.jpg'),
(28, 'Scream 7', "Scream 7 marque le retour de Sidney Prescott, désormais mère prête à tout pour protéger sa fille lorsqu'un nouveau Ghostface frappe dans sa ville paisible. Mêlant héritage de la saga et thèmes modernes comme l'obsession des fans ou l'IA, le film alterne tension, rebondissements et clins d'œil nostalgiques.", 'Horreur', 2026, 'https://image.tmdb.org/t/p/w500/jjyuk0edLiW8vOSnlfwWCCLpbh5.jpg'),
(29, 'Paranormal Activity', "L'histoire commence le 18 septembre 2006. Micah retrouve sa petite amie Katie avec sa nouvelle caméra dans leur nouvelle maison dans la banlieue de San Diego, en Californie. Katie prétend qu'une présence surnaturelle la hante depuis l'enfance, et estime que cela l'a suivie jusqu'à leur nouvelle maison. Chaque nuit, Micah monte une caméra vidéo sur un trépied dans leur chambre pour enregistrer toute activité paranormale qui pourrait se produire pendant leur sommeil, dans l'espoir de résoudre le problème.", 'Horreur', 2009, 'https://image.tmdb.org/t/p/w500/tmclkEpjeo4Zu564gf3KrwIOuKw.jpg'),
(30, 'Hush', "Maddie Young est une jeune écrivaine sourde et muette ayant décidé de s'installer seule dans une maison au fond des bois, espérant que le calme et la solitude lui permettraient de retrouver l'inspiration pour écrire son prochain livre. Après une petite visite amicale de sa voisine, Sarah, elle ne se doute pas le moins du monde de la présence d'une autre personne près de la maison, un homme masqué et sadique qui est bien décidé à la tuer.", 'Horreur', 2016, 'https://image.tmdb.org/t/p/w500/tyqD4C2vVKrvP3FkFK0GS9IWbTo.jpg'),
(31, 'Until Dawn', "Until Dawn : La Mort sans fin entraîne Clover et ses amis dans une vallée isolée où, chaque nuit, ils meurent sous des formes différentes et revivent le même cauchemar, avec un nombre limité de vies et l'espoir de tenir jusqu'à l'aube.", 'Horreur', 2025, 'https://image.tmdb.org/t/p/w500/bLY5yN4MKVynZ2HMZWElTOGBgBe.jpg'),
(32, 'Hereditary', "Le film suit la famille Graham, dont la matriarche, Ellen, décède. Annie, sa fille, est une artiste maquettiste qui vit avec son mari Steve et leurs deux enfants, Peter et Charlie. Après les funérailles d'Ellen, la famille commence à découvrir des secrets troublants sur leur lignée. Annie participe à un groupe de soutien où elle partage des détails sur son enfance difficile et la relation tendue qu'elle avait avec sa mère...", 'Horreur', 2018, 'https://image.tmdb.org/t/p/w500/4GFPuL14eXi66V96xBWY73Y9PfR.jpg'),
(33, 'SAW X', "Saw X se situe entre les deux premiers volets et met au centre John Kramer, malade et désespéré, qui part au Mexique pour un traitement expérimental contre son cancer avant de découvrir une arnaque visant les plus vulnérables. Plus narratif et centré sur la psychologie du tueur, il alterne tensions et pièges sanglants.", 'Horreur', 2023, 'https://image.tmdb.org/t/p/w500/u7Lp1Hi8aBS73jv4KRMIv5aK4ax.jpg'),
(34, 'Les Oiseaux', "Les Oiseaux d'Alfred Hitchcock met en scène Melanie Daniels, jeune mondaine de San Francisco, qui suit un avocat jusqu'à la paisible Bodega Bay où des phénomènes étranges surviennent : des centaines d'oiseaux se mettent à attaquer les habitants.", 'Horreur', 1963, 'https://image.tmdb.org/t/p/w500/bRW95eVqlNhVmfz4fCQZvJ83TUV.jpg'),
(35, 'Heretic', "Deux jeunes missionnaires de l'église mormone d'une petite ville du Colorado font du porte à porte dans l'espoir de convertir les habitants. Le soir venu, après une journée infructueuse, elles décident de frapper à la porte d'une maison isolée. C'est le charmant Mr Reed qui les y accueille. Mais très vite, les jeunes femmes réalisent qu'elles sont tombées dans un piège. La maison est un véritable labyrinthe où elles ne pourront compter que sur leur ingéniosité et leur intelligence pour rester en vie...", 'Horreur', 2000, 'https://image.tmdb.org/t/p/w500/fr96XzlzsONrQrGfdLMiwtQjott.jpg'),
(36, 'Sans un Bruit', "Dans le nord de l'État de New York, un couple et ses deux enfants doivent rester silencieux dans leur ferme isolée pour éviter des créatures mystérieuses qui utilisent le son pour chasser leurs proies. En utilisant le langage des signes et le contact visuel pour communiquer, les membres de la famille doivent compter les uns sur les autres et sur leur intelligence pour survivre.", 'Horreur', 2018, 'https://image.tmdb.org/t/p/w500/hSPJiayIoPTUL8eq3cgwzAjZV7K.jpg'),
(37, 'Us', "Us est un thriller horrifique de Jordan Peele où Adelaide Wilson, en vacances avec sa famille à Santa Cruz, voit ressurgir un traumatisme enfoui. Leur séjour vire au cauchemar lorsqu'un groupe d'inconnus surgit… à leur image.", 'Horreur', 2019, 'https://image.tmdb.org/t/p/w500/ux2dU1jQ2ACIMShzB3yP93Udpzc.jpg'),
(38, 'Get Out', "Get Out est un thriller horrifique et satirique où Chris, un jeune photographe afro-américain, rend visite pour la première fois à la famille de sa petite amie blanche. Ce qui commence comme un week-end apparemment cordial vire peu à peu à l'inquiétude face à des comportements étranges, révélant une menace insoupçonnée...", 'Horreur', 2017, 'https://image.tmdb.org/t/p/w500/mE24wUCfjK8AoBBjaMjho7Rczr7.jpg'),
(39, 'Le Rituel', "Cinq amis de longue date discutent de la destination de leurs prochaines vacances. Luke et Robert vont ensuite dans une épicerie de nuit acheter de l'alcool pendant que Phil, Dom et Hutch les attendent dans la rue. Mais un braquage est en cours dans le commerce et Robert est tué pendant que Luke demeure caché dans le magasin.", 'Horreur', 2017, 'https://image.tmdb.org/t/p/w500/lLRGvZqToTPIIbL2iqAcTPPpKjA.jpg'),
(40, 'Harry Potter', "Harry Potter, un jeune orphelin, est élevé par son oncle et sa tante qui le détestent. Le jour de son onzième anniversaire, Harry reçoit la visite inattendue d'un homme gigantesque se nommant Rubeus Hagrid, et celui-ci lui révèle qu'il est en fait le fils de deux puissants magiciens et qu'il possède lui aussi d'extraordinaires pouvoirs.", 'Fantastique', 2001, 'https://image.tmdb.org/t/p/w500/fECBtHlr0RB3foNHDiCBXeg9Bv9.jpg'),
(41, 'Percy Jackson et le voleur de foudre', "Toujours prédisposée à des problèmes, la vie d'adolescent de Percy Jackson devient beaucoup plus compliquée quand il apprend qu'il est le fils de dieu grec Poséidon. À une terre d'entraînement pour les enfants de divinités, Percy apprend à exploiter ses pouvoirs divins et à se préparer à l'aventure d'une vie: il doit empêcher une querelle parmi les Olympians d'entrer en éruption dans une guerre ravageuse sur la Terre et sauver sa mère des prises de Hadès, dieu des enfers.", 'Fantastique', 2010, 'https://image.tmdb.org/t/p/w500/placeholder.jpg'),
(42, 'Le Seigneur des Anneaux', "la Terre du Milieu est menacée par Sauron, le Seigneur des Ténèbres, qui cherche à récupérer l'Anneau unique qu'il a forgé pour contrôler tous les autres anneaux et asservir les peuples. Frodon Sacquet, un hobbit du Comté, hérite de cet anneau de son oncle Bilbon et se voit confier la mission périlleuse de le détruire dans les feux du Mont Doom, au cœur du Mordor", 'Fantastique', 2001, 'https://image.tmdb.org/t/p/w500/btkqen3PiBsEJDoPcHDtgmKGVFu.jpg'),
(43, 'Le Hobbit', "Bilbon Sacquet, un hobbit tranquille de la Comté, est recruté par le magicien Gandalf et treize nains menés par Thorin Écu-de-Chêne pour participer à une expédition visant à reconquérir le royaume d'Erebor, occupé par le dragon. Au cours de leur périple, ils affrontent des trolls, des gobelins et des orques. Bilbon rencontre Gollum dans les tunnels souterrains et découvre l'anneau unique, qui deviendra central dans l'univers de la Terre du Milieu.", 'Fantastique', 2012, 'https://image.tmdb.org/t/p/w500/zzvnyLZjsI6RN5qETxb4YuI4FlN.jpg'),
(44, 'Avatar', "En l'an 2154, Jake Sully, ancien marine paraplégique, accepte de participer au programme Avatar pour remplacer son frère jumeau décédé, Tom Sully. Il est envoyé sur Pandora, l'une des lunes de Polyphème, une planète géante gazeuse en orbite autour d'Alpha Centauri A. Cette dernière est l'étoile principale du système stellaire Alpha Centauri, situé à 4,4 années-lumière du Système solaire.", 'Fantastique', 2009, 'https://image.tmdb.org/t/p/w500/gKY6q7SjCkAU6FqvqWybDYgUKIF.jpg'),
(45, 'Les Animaux Fantastiques', "En 1926, Norbert Dragonneau rentre à peine d'un périple à travers le monde où il a répertorié un bestiaire extraordinaire de créatures fantastiques. Il pense faire une courte halte à New York, mais une série d'événements et de rencontres inattendues risquent de prolonger son séjour. Désormais, le monde de la magie est menacé.", 'Fantastique', 2016, 'https://image.tmdb.org/t/p/w500/wcdlsiw5fIVteprvq8a6VyRsFHN.jpg'),
(46, 'Wicked', "Au pays d'Oz, les habitants de Munchkinland célèbrent la mort de la Méchante sorcière de l'Ouest. La Bonne Glinda leur raconte alors son histoire : la sorcière est née d'une liaison entre la femme du gouverneur Thropp et un marchand. Son amant lui donna un élixir vert qu'elle but. Elle tomba enceinte et donna naissance à une fille à la peau verte, Elphaba. Dès sa naissance, Elphaba faisait face aux moqueries et au rejet du fait de sa couleur de peau. Une habitante demande à Glinda si elle et Elphaba étaient amies. Elle avoue que oui et commence à raconter l'histoire de leur amitié...", 'Fantastique', 2024, 'https://image.tmdb.org/t/p/w500/xDGbZ0JJ3mYaGKy4Nzd9Kph6M9L.jpg'),
(47, 'Willow', "La cruelle reine Bavmorda règne sur le peuple des Daïkinis. Lorsqu'une prédiction annonce la naissance imminente d'une princesse qui la détrônera, Bavmorda donne l'ordre de tuer tous les nouveau-nés du royaume. Elora, le bébé de la prophétie, échappe au massacre. Elle est recueillie par Willow, un homme de petite taille qui fait partie de la race des Nelwyns. Ce dernier est chargé de ramener l'enfant au pays des Daïkinis.", 'Fantastique', 1988, 'https://image.tmdb.org/t/p/w500/pAIRGMIdN7ZdZhflazdV2ezuJ9f.jpg'),
(48, 'Gremlins', "Randall Peltzer, est un inventeur farfelu aux créations allant des plus pratiques aux plus originales. Originaire de Kingston Falls, il se rend dans le quartier de Chinatown à New York, pour tenter de vendre ses inventions et dénicher un cadeau de Noël original pour son fils Billy. Un jeune Chinois l'emmène au magasin de son grand-père, M. Wing, et faute d'arriver à placer une de ses inventions comme la « salle de bains de poche », il se prend d'intérêt pour une petite créature à fourrure, un mogwaï. Mais M. Wing refuse catégoriquement de vendre le mogwaï malgré l'offre de deux cents dollars de Rand. Selon lui, prendre en charge le petit animal entraîne de trop lourdes responsabilités pour son acquéreur.", 'Fantastique', 1984, 'https://image.tmdb.org/t/p/w500/6m0F7fsXjQvUbCZrPWcJNrjvIui.jpg'),
(49, 'Hellboy', "Hellboy (2019), reboot de la saga adapté des comics de Mike Mignola, suit le célèbre démon enquêteur du B.P.R.D. envoyé à Londres pour affronter la redoutable Reine de Sang, revenue d'outre-tombe pour détruire l'humanité.", 'Fantastique', 2019, 'https://image.tmdb.org/t/p/w500/bk8LyaMqUtaQ9hUShuvFznQYQKR.jpg'),
(50, 'Jumanji', "Après avoir découvert une vieille console contenant un jeu vidéo dont ils n'avaient jamais entendu parler, quatre jeunes se retrouvent mystérieusement propulsés au cœur de la jungle de Jumanji, dans le corps de leurs avatars. Ils découvrent rapidement que l'on ne joue pas à Jumanji, mais que c'est le jeu qui joue avec vous. Pour revenir dans le monde réel, il va leur falloir affronter les pires dangers et triompher de l'ultime aventure. Sinon, ils resteront à jamais prisonniers du jeu.", 'Fantastique', 2017, 'https://image.tmdb.org/t/p/w500/iWV47r6kFneCiApgrMII5HSkfHw.jpg'),
(51, 'Alice au Pays des Merveilles', "Alice s'ennuie auprès de sa sœur qui lit un livre tandis qu'elle ne fait rien. Mais voilà qu'un lapin blanc aux yeux roses vêtu d'une redingote avec une montre à gousset à y ranger passe près d'elle en courant...", 'Fantastique', 1951, 'https://image.tmdb.org/t/p/w500/vXcHOl6MmhOkJO64wNrNDnpp86m.jpg'),
(52, 'Peter Pan', "La famille Darling vit à Londres. Chaque soir, Wendy émerveille ses jeunes frères avec ses fantastiques récits épiques narrant les aventures de Peter Pan au Pays Imaginaire.", 'Fantastique', 2004, 'https://image.tmdb.org/t/p/w500/6QdU3TZZrIvXFzoHOwafZAynFjB.jpg'),
(53, "Donjons et Dragons : L'Honneur des voleurs", "Un voleur attachant et un groupe d'aventuriers disparates entreprennent un raid risqué pour récupérer une relique perdue. Mais leur mission risque d'échouer lorsqu'ils s'attaquent aux mauvaises personnes en chemin. L'homme qui détient la relique tant convoitée après un vol est également dangereux : il fait cause commune avec un puissant sorcier rouge et élabore de sombres plans pour l'avenir.", 'Fantastique', 2023, 'https://image.tmdb.org/t/p/w500/placeholder.jpg'),
(54, 'Loups-garous', "Quand un vieux jeu de cartes prend vie, une famille remonte le temps et atterrit dans un village médiéval où il lui faudra démasquer des loups-garous pour pouvoir revenir à son époque.", 'Fantastique', 2024, 'https://image.tmdb.org/t/p/w500/8KSWUx4HNxfT2Klyl8lUpm1AVl7.jpg'),
(55, 'Men in Black', "Chargés de protéger la Terre de toute infraction extraterrestre et de réguler l'immigration intergalactique sur notre planète, les Men in black ou MIB opèrent dans le plus grand secret. Vêtus de costumes sombres et équipés des toutes dernières technologies, ils passent inaperçus aux yeux des humains dont ils effacent régulièrement la mémoire récente.", 'Science-Fiction', 1997, 'https://image.tmdb.org/t/p/w500/uLOmOF5IzWoyrgIF5MfUnh5pa1X.jpg'),
(56, 'Hunger Games', "Après que sa sœur a été sélectionnée pour participer aux violents 'Hunger Games', Katniss Everdeen décide de se porter volontaire pour libérer sa sœur de son fardeau. La jeune femme et son comparse du District 12, Peeta, devront affronter 22 autres adolescents ayant entre 12 et 18 ans, jusqu'à la mort.", 'Science-Fiction', 2012, 'https://image.tmdb.org/t/p/w500/yXCbOiVDCxO71zI7cuwBRXdftq8.jpg'),
(57, 'Interstellar', "En 2067, la Terre est devenue de moins en moins accueillante pour l'humanité plongée dans une grave crise alimentaire. L'humanité est tellement résignée à son destin que les écoles enseignent que les missions Apollo n'ont jamais eu lieu et n'étaient que des impostures destinées à ruiner l'URSS.", 'Science-Fiction', 2014, 'https://image.tmdb.org/t/p/w500/yQvGrMoipbRoddT0ZR8tPoR7NfX.jpg'),
(58, 'Retour vers le Futur', "Le jeune Marty McFly mène une existence anonyme, auprès de sa petite amie Jennifer, seulement troublée par sa famille en crise et un proviseur qui serait ravi de l'expulser du lycée. Ami de l'excentrique professeur Emmett Brown, il l'accompagne tester sa nouvelle expérience : le voyage dans le temps via une DeLorean modifiée. La démonstration tourne mal : des trafiquants d'armes débarquent et assassinent le scientifique.", 'Science-Fiction', 1985, 'https://image.tmdb.org/t/p/w500/eZNtT3h5xMY89kTPHfPFmWLKkVU.jpg'),
(59, 'Inception', "Dom Cobb est un voleur expérimenté dans l'art périlleux de l'extraction : sa spécialité consiste à s'approprier les secrets les plus précieux d'un individu, enfouis au plus profond de son subconscient, pendant qu'il rêve et que son esprit est particulièrement vulnérable. Très recherché pour ses talents dans l'univers trouble de l'espionnage industriel, Cobb est aussi devenu un fugitif traqué dans le monde entier. Cependant, une ultime mission pourrait lui permettre de retrouver sa vie d'avant.", 'Science-Fiction', 2010, 'https://image.tmdb.org/t/p/w500/xlaY2zyzMfkhk0HSC5VUwzoZPU1.jpg'),
(60, 'Maze Runner', "Quand Thomas reprend connaissance, il est pris au piège avec un groupe d'autres garçons dans un labyrinthe géant dont le plan est modifié chaque nuit. Il n'a plus aucun souvenir du monde extérieur, à part d'étranges rêves à propos d'une mystérieuse organisation appelée W.C.K.D. En reliant certains fragments de son passé, avec des indices qu'il découvre au sein du labyrinthe, Thomas espère trouver un moyen de s'en échapper.", 'Science-Fiction', 2014, 'https://image.tmdb.org/t/p/w500/ode14q7WtDugFDp78fo9lCsmay9.jpg'),
(61, 'SOS Fantômes', "La soudaine recrudescence de phénomènes paranormaux commence à inquiéter les habitants de New York. En effet, des revenants sèment la pagaille dans toutes les rues de la ville. Peter Venkman, Raymond «Ray» Stantz et Egon Spengler, trois jeunes chercheurs en parapsychologie de l'université de Columbia, décident alors de monter leur propre société d'investigations paranormales, qu'ils nomment «SOS Fantômes».", 'Science-Fiction', 1984, 'https://image.tmdb.org/t/p/w500/7E8nLijS9AwwUEPu2oFYOVKhdFA.jpg'),
(62, 'Dernière Chance', "Projet Dernière Chance suit Ryland Grace, professeur de sciences, qui se réveille seul à bord d'un vaisseau, sans souvenir, à des années-lumière de la Terre. Peu à peu, il découvre qu'il est au cœur d'une mission cruciale pour empêcher l'extinction du Soleil. Entre science, ingéniosité et une rencontre inattendue, le film offre un mélange rare de tension spatiale, d'humour et d'émotion, salué pour ses images spectaculaires et son humanité.", 'Science-Fiction', 2026, 'https://image.tmdb.org/t/p/w500/94gBGnMBH9xkM8agnMkQensuNjm.jpg'),
(63, 'La Planète des Singes', "L'engin spatial américain Icare, parti en 19721 avec à son bord 4 membres d'équipage, traverse l'espace à une vitesse proche de la vitesse de la lumière. Au terme d'un voyage de 18 mois, le vaisseau s'écrase le 25 novembre 39782 sur une mystérieuse planète, au coeur d'une région désertique. Les 3 survivants du crash, le capitaine George Taylor et les lieutenants John Landon et Thomas Dodge, découvrent très vite que ce monde est peuplé d'hommes primitifs dominés par une race de singes évolués.", 'Science-Fiction', 1968, 'https://image.tmdb.org/t/p/w500/j55l5cAP2Pc3O4UF70DQU0FIEUU.jpg'),
(64, 'The Darkest Hour', "Sean et Ben sont à Moscou pour affaires, Natalie et Anne en escale involontaire alors qu'elles se rendaient au Népal. Les quatre jeunes gens se rencontrent par hasard dans la boîte de nuit la plus branchée de la ville. Ce haut lieu qui attire puissants et personnalités en vue bascule dans la terreur lorsque des aliens attaquent. Ils se réfugient en sous-sol puis, seuls survivants avec Skylar, un businessman menaçant, ils découvrent une ville détruite.", 'Science-Fiction', 2011, 'https://image.tmdb.org/t/p/w500/iUrtHcc8rn7iX31Id3MYOT1rbyw.jpg'),
(65, 'Snowpiercer', "À la suite d'une tentative ratée d'une entreprise de géo-ingénierie pour contrebalancer le réchauffement climatique en 2014, par envoi d'un gaz dans l'atmosphère, une glaciation de toute la planète extermine la vie sur terre, ainsi que presque toute l'humanité. Les survivants vivent désormais tous dans un train lancé à vive allure, Le Transperceneige, dirigé par Wilford, le créateur de celui-ci qui réside dans le wagon de tête.", 'Science-Fiction', 2013, 'https://image.tmdb.org/t/p/w500/kw6YQudA0TMcNmGUGy5XIw7zbnV.jpg'),
(66, 'E.T.', "E.T., l'extra-terrestre suit l'amitié entre Elliott, un garçon solitaire, et un extraterrestre perdu sur Terre. Ensemble, ils cherchent à permettre à E.T. de rentrer chez lui tout en échappant aux autorités.", 'Science-Fiction', 1982, 'https://image.tmdb.org/t/p/w500/an0nD6uq6byfxXCfk6lQBzdL2J1.jpg'),
(67, 'Mickey 17', "Mickey 17 plonge dans un futur glacial où Mickey Barnes, « remplaçable » cloné après chaque mort, affronte une mission périlleuse sur la planète Niflheim et la découverte d'un double inattendu.", 'Science-Fiction', 2025, 'https://image.tmdb.org/t/p/w500/edKpE9B5qN3e559OuMCLZdW1iBZ.jpg'),
(68, 'Dans la Brume', "Le jour où une étrange brume mortelle submerge Paris, des survivants trouvent refuge dans les derniers étages des immeubles et sur les toits de la capitale. Sans informations, sans électricité, sans eau ni nourriture, une petite famille tente de survivre à cette catastrophe. Cependant, les heures passent et un constat s'impose : les secours ne viendront pas et il faudra, pour espérer s'en sortir, tenter sa chance dans la brume.", 'Science-Fiction', 2018, 'https://image.tmdb.org/t/p/w500/hjePJQDv7GitTrEU67TANuhbytv.jpg'),
(69, 'Gravity', "Le commandant de la navette spatiale américaine Explorer, Mathieu Kowalski, et l'astronaute scientifique Ryan Stone, seuls survivants d'une mission spatiale destinée à réparer le télescope spatial Hubble, tentent de retourner sur Terre en regagnant d'abord la Station spatiale internationale.", 'Science-Fiction', 2013, 'https://image.tmdb.org/t/p/w500/kZ2nZw8D681aphje8NJi8EfbL1U.jpg'),
(70, 'Divergente', "Tris vit dans un monde post-apocalyptique où la société est divisée en cinq clans. À 16 ans, elle doit choisir son appartenance pour le reste de sa vie. Cas rarissime, son test d'aptitude n'est pas concluant : elle est Divergente. Les Divergentes sont des individus rares n'appartenant à aucun clan et ils sont traqués par le gouvernement. Dissimulant son secret, Tris intègre l'univers brutal des Audacieux dont l'entraînement est basé sur la maîtrise de leurs peurs les plus intimes.", 'Science-Fiction', 2014, 'https://image.tmdb.org/t/p/w500/riyO8IN3gts4VuQhLJmHjkD9xIF.jpg'),
(71, 'James Bond - Spectre', "James Bond, incité à enquêter sur l'organisation secrète à but terroriste SPECTRE à la suite d'un testament vidéo laissé par l'ancienne M, morte dans Skyfall. Alors que le nouveau M fait face à la volonté du Home Office de supprimer la section 00 des services secrets britanniques, Bond s'allie avec la fille d'un ancien ennemi, Madeleine Swann, afin d'affronter SPECTRE.", 'Action', 2015, 'https://image.tmdb.org/t/p/w500/pGiIDZFEZLPFZTecPyyKVNKjeMs.jpg'),
(72, 'The Batman', "Batman a été confronté à des situations inimaginables et n'a pu compter que sur une poignée d'alliés. Quand en cette année électorale, un tueur s'en prend à l'élite de la ville, le justicier se lance à sa poursuite. Il est guidé par une série d'indices cryptés qui l'envoient enquêter au cœur même de la pègre de Gotham City. Au fur et à mesure que tout s'éclaircit et que Batman est de plus en plus proche de sa cible, il est obligé de nouer de nouvelles alliances. Il y est contraint s'il veut atteindre sa cible, rétablir la justice et essayer d'éradiquer la corruption qui règne depuis fort longtemps à Gotham.", 'Action', 2022, 'https://image.tmdb.org/t/p/w500/74xTEgt7R36Fpooo50r9T25onhq.jpg'),
(73, 'Spider-Man : No Way Home', "Après que l'identité de Spider-Man a été révélée par Mystério, Peter Parker est poursuivi par le gouvernement et les médias, mettant en danger ses proches. Pour restaurer son anonymat, il demande l'aide du Docteur Strange, qui lance un sort pour faire oublier à tous que Peter est Spider-Man. Le sort tourne mal, ouvrant le multivers et faisant apparaître des ennemis d'autres univers. Peter doit alors capturer et guérir ces «visiteurs» avant qu'ils ne subissent leur destin tragique, tout en affrontant des défis personnels et émotionnels majeurs.", 'Action', 2021, 'https://image.tmdb.org/t/p/w500/1g0dhYtq4irTY1GPXvft6k4YLjm.jpg'),
(74, 'Fast and Furious', "La nuit tombée, Dominic Toretto règne sur les rues de Los Angeles à la tête d'une équipe de fidèles qui partagent son goût du risque, sa passion de la vitesse et son culte des voitures de sport lancées à plus de 250 km/h dans des rodéos urbains d'une rare violence. Ses journées sont consacrées à bricoler et à relooker des modèles haut de gamme, à les rendre toujours plus performants et plus voyants, et à organiser des joutes illicites.", 'Action', 2001, 'https://image.tmdb.org/t/p/w500/rdQrh59Gq0DX8OmoQeECUtBkoH5.jpg'),
(75, 'La Momie', "1719 avant J.-C. Pour avoir osé ravir sa fiancée au Pharaon, le grand prêtre Imhotep est momifié vivant et enseveli dans une crypte secrète d'Hamunaptra, mais son cœur bat toujours et la Momie attend l'heure de sa libération. En 1923, l'aventurier O'Connell découvre les ruines d'Hamunaptra. La malédiction d'Imhotep va pouvoir se réaliser.", 'Action', 1999, 'https://image.tmdb.org/t/p/w500/5RfBXTirkL4yaHHSs3XVpg86InL.jpg'),
(76, 'Skyscraper', "Ancien chef du commando de libération des otages du FBI et vétéran de l'armée américaine, Will Sawyer est désormais responsable de la sécurité des gratte-ciel. Alors qu'il est affecté à Hong Kong, il est accusé d'avoir déclenché un incendie dans la tour la plus haute et réputée la plus sûre du monde. Considéré comme fugitif, Will doit retrouver les criminels, prouver son innocence et surtout sauver sa femme et ses deux enfants prisonniers du bâtiment en flammes.", 'Action', 2018, 'https://image.tmdb.org/t/p/w500/52ml62vClzrlqvXZq2FEW6UF6c1.jpg'),
(77, 'Léon', "Léon suit un tueur à gages solitaire à New York qui se retrouve à protéger Mathilda, une fillette de 12 ans, unique survivante du massacre de sa famille, et à lui transmettre les bases de son métier. Mélange intense de drame, d'action et de tension psychologique, le film impressionne par la mise en scène de Luc Besson, le jeu marquant de Jean Reno, Natalie Portman et Gary Oldman, et une atmosphère inoubliable.", 'Action', 1994, 'https://image.tmdb.org/t/p/w500/bxB2q91nKYp8JNzqE7t7TWBVupB.jpg'),
(78, 'Matrix', "Matrix plonge dans un futur dystopique où la réalité perçue est une simulation créée par des machines pour asservir l'humanité. Lorsque Neo, un hacker, découvre cette vérité grâce à un groupe de rebelles, il doit choisir entre continuer à vivre dans l'illusion ou combattre pour la liberté. Alliant action spectaculaire, esthétique cyberpunk et réflexions philosophiques, le film est salué comme une révolution de la science-fiction et reste une œuvre culte incontournable.", 'Action', 1999, 'https://image.tmdb.org/t/p/w500/aOIuZAjPaRIE6CMzbazvcHuHXDc.jpg'),
(79, 'Speed', "Speed (1994) suit un jeune policier de Los Angeles confronté à un maître chanteur prêt à tout pour semer la panique : un autobus est piégé et explosera s'il ralentit en dessous de 80 km/h. Porté par un concept simple et efficace, ce thriller d'action haletant multiplie les cascades spectaculaires et maintient une tension constante. L'alchimie entre Keanu Reeves et Sandra Bullock, alliée à une mise en scène nerveuse, en fait un classique du genre, toujours aussi efficace à revoir.", 'Action', 1994, 'https://image.tmdb.org/t/p/w500/1qeO6qbbOXFkwN19aCWQAlmpbHQ.jpg'),
(80, 'Bad Boys', "Si Mike Lowrey est un séducteur invétéré, héritier d'une fortune et policier par passion, son collègue et ami Marcus Burnett est un homme rangé, marié et père de famille. Leur amitié ne les empêche cependant pas d'avoir des méthodes parfaitement différentes.", 'Action', 1995, 'https://image.tmdb.org/t/p/w500/x1ygBecKHfXX4M2kRhmFKWfWbJc.jpg'),
(81, 'Gladiator', "Le général romain Maximus est le plus fidèle soutien de l'empereur Marc Aurèle, qu'il a conduit de victoire en victoire. Jaloux du prestige de Maximus, et plus encore de l'amour que lui voue l'empereur, le fils de Marc Aurèle, Commode, s'arroge brutalement le pouvoir, puis ordonne l'arrestation du général et son exécution. Maximus échappe à ses assassins, mais ne peut empêcher le massacre de sa famille. Capturé par un marchand d'esclaves, il devient gladiateur et prépare sa vengeance.", 'Action', 2024, 'https://image.tmdb.org/t/p/w500/wN2xWp1eIwCKOD0BHTcErTBv1Uq.jpg'),
(82, 'Un homme en colère', "Alex, un Américain traversant une période difficile, se trouve un travail auprès d'une entreprise londonienne de camions blindés, gagnant la confiance d'une équipe de braquage dont les membres entretiennent une amitié serrée. Or, il s'en cache bien plus derrière l'apparence d'Alex. Tandis qu'il adopte des mesures dangereuses et moralement complexes pour poursuivre son mystérieux agenda, un secret perturbant de son passé refait surface.", 'Action', 2021, 'https://image.tmdb.org/t/p/w500/A2GPFdxQRT99uHkha7NNVMkustQ.jpg'),
(83, 'Jumper', "David Rice a toujours cru qu'il était parfaitement ordinaire avant qu'il ne découvre par accident qu'il possède un don. David est un Jumper, qui peut se téléporter partout où il veut.", 'Action', 2008, 'https://image.tmdb.org/t/p/w500/3pPZ9JhNz3VMmASVir5SMHvTDUU.jpg'),
(84, 'Taxi', "Daniel est un fou du volant. Cet ex-livreur de pizzas est aujourd'hui chauffeur de taxi et sait échapper aux radars les plus perfectionnés. Pourtant, un jour, il croise la route d'Émilien, policier recalé pour la huitième fois à son permis de conduire. Pour conserver son taxi, il accepte le marché que lui propose Émilien : l'aider à démanteler un gang de braqueurs de banques qui écume les succursales de la ville à bord de puissants véhicules.", 'Action', 1998, 'https://image.tmdb.org/t/p/w500/ekstpH614fwDX8DUln1a2Opz0N8.jpg'),
(85, 'Les Gardiens de la Galaxie', "Les Gardiens de la Galaxie suit Peter Quill, aventurier interstellaire, qui s'allie à un raton laveur expert en armes, un humanoïde arbre, une guerrière énigmatique et un destructeur assoiffé de vengeance pour contrer un ennemi menaçant l'univers...", 'Action', 2014, 'https://image.tmdb.org/t/p/w500/y4MBh0EjBlMuOzv9axM4qJlmhzz.jpg'),
(86, 'Pulp Fiction', "Pulp Fiction est un film culte de Quentin Tarantino qui entremêle, avec une narration non linéaire, plusieurs histoires autour de gangsters, truands et marginaux à Los Angeles. Dialogues incisifs, humour noir et violence stylisée s'y mêlent dans une fresque pop et postmoderne.", 'Action', 1994, 'https://image.tmdb.org/t/p/w500/vQWk5YBFWF4bZaofAbv0tShwBvQ.jpg'),
(87, 'Deadpool & Wolverine', "Deadpool et Wolverine (2024) réunit pour la première fois à l'écran l'anti-héros bavard Deadpool et le mutant Wolverine. Recruté par le Tribunal des Variations Anachroniques pour une mission qui pourrait changer le multivers, Deadpool retrouve un Wolverine venu d'un autre univers et tente de le convaincre de sauver sa réalité...", 'Action', 2024, 'https://image.tmdb.org/t/p/w500/8cdWjvZQUExUUTzyp4t6EDMubfO.jpg'),
(88, "Mission Impossible", "l'agent Ethan Hunt, accusé à tort de trahison après l'échec d'une mission à Prague. Traqué, il doit identifier le vrai traître et déjouer un complot tout en opérant seul, avec l'aide d'alliés inattendus, pour récupérer des informations ultrasecrètes et laver son nom.", 'Action', 1996, 'https://image.tmdb.org/t/p/w500/l5uxY5m5OInWpcExIpKG6AR3rgL.jpg'),
(89, "Asterix et Obélix - Mission Cléopâtre", "Mission Cléopâtre est un film qui mêle humour, action et aventures. Le récit suit Cléopâtre, la reine d'Égypte, qui, pour impressionner Jules César, décide de construire un palais en plein désert en trois mois. Elle fait appel à l'architecte Numérobis, qui, pour éviter d'être jeté aux crocodiles sacrés, demande de l'aide à Panoramix, un druide gaulois. Les trois personnages doivent alors affronter les manigances d'Amonbofis, l'architecte royal jaloux, et des Romains pour réaliser le palais.", 'Comédie', 2002, 'https://image.tmdb.org/t/p/w500/jdAWJpSjSsROflDE5e7fgxJu2KW.jpg'),
(90, "Maman j'ai raté l'avion", "La famille McCallister a décidé de passer les fêtes de Noël à Paris. Seulement Kate et Peter McCallister s'aperçoivent dans l'avion qu'il leur manque le plus jeune de leurs enfants, Kevin, âgé de neuf ans. D'abord désespéré, Kevin reprend vite les choses en main et s'organise pour vivre le mieux possible. Cependant, deux cambrioleurs choisissent sa maison pour commettre leurs méfaits.", 'Comédie', 1990, 'https://image.tmdb.org/t/p/w500/uuitWHpJwxD1wruFl2nZHIb4UGN.jpg'),
(91, "OSS 117 - Le Caire, nid d'espions", "En 1945, à la fin de la Seconde Guerre mondiale, Hubert Bonisseur de la Bath et Jack Jefferson, deux agents des Forces françaises libres, effectuent une mission pour les Alliés où ils parviennent à détourner l'avion allemand du colonel Von Umpsprung et à dérober les plans du V2, l'arme absolue de l'Allemagne nazie.", 'Comédie', 2006, 'https://image.tmdb.org/t/p/w500/dDVHVZVEbTV4JsB8ZjdXNmMK7rA.jpg'),
(92, "Un p'tit truc en plus", "Pour échapper à la police, un fils et son père en cavale sont contraints de trouver refuge dans une colonie de vacances pour jeunes adultes en situation de handicap, se faisant passer pour un pensionnaire et son éducateur spécialisé. Le début des problèmes et d'une formidable expérience humaine qui va les changer à jamais.", 'Comédie', 2024, 'https://image.tmdb.org/t/p/w500/hhL8QC7O6fFfwgV6pDf1WSOxGcY.jpg'),
(93, "The Truman Show", "Depuis qu'il est né et qu'un studio de télévision l'a officiellement adopté, Truman Burbank est, sans qu'il le sache, le héros d'une émission de télé-réalité filmée 24 heures sur 24 et 7 jours sur 7 par plus de 5 000 caméras cachées : The Truman Show. Christof, le créateur et producteur exécutif de l'émission, cherche à saisir les émotions authentiques du héros.", 'Comédie', 1998, 'https://image.tmdb.org/t/p/w500/vuza0WqY239yBXOadKlGwJsZJFE.jpg'),
(94, "Maison de retraite", "Afin d'éviter la case prison, Milann, 30 ans, est contraint d'effectuer 300 heures de travaux d'intérêt général dans une maison de retraite. Ses premières semaines sont un véritable enfer, mais il se fait rapidement adopter par les retraités qui lui apprennent leur vision de la vie. Au fil des semaines, Milann découvre que l'établissement profite de la vulnérabilité de ses pensionnaires pour les arnaquer. Il décide alors d'organiser une grande évasion, mais il n'est pas au bout de ses peines.", 'Comédie', 2022, 'https://image.tmdb.org/t/p/w500/lLrCA0MaLFZS518fkaeMUavJOGG.jpg'),
(95, "Murder Mystery", "Un inspecteur de la police de New York part en voyage avec sa femme à travers l'Europe. Dans leur avion, ils font la rencontre d'un homme mystérieux qui les invite à une soirée familiale, en petit comité qui a lieu sur le yacht d'un milliardaire âgé. Quand l'homme riche est assassiné, ils deviennent les principaux suspects de l'agent d'InterpolLaur...", 'Comédie', 2019, 'https://image.tmdb.org/t/p/w500/bSMSO9xupd4R4vwTPqigHn2quLN.jpg'),
(96, "Les Tuches", "La saga suit la famille Tuche, originaire de la commune fictive de Bouzolles dans le Limaret, composée de Jeff Tuche, père chômeur et fier de l'être, Cathy, sa femme, leurs trois enfants Stéphanie, fan de téléréalité, Wilfried, un jeune homme naïf et en quête de son identité, et Donald, surnommé «Coin-Coin», surdoué ainsi que Mamie Suze, la grand-mère excentrique parlant un charabia incompréhensible que seule Cathy comprend..", 'Comédie', 2011, 'https://image.tmdb.org/t/p/w500/ntBV03zpD63GHXlU5YM5inmzsRu.jpg'),
(97, "Qu'est ce qu'on a fait au bon dieu ?", "Claude et Marie Verneuil, issus de la grande bourgeoisie catholique provinciale sont des parents plutôt vieille France. Cependant, ils se sont toujours obligés à faire preuve d'ouverture d'esprit. Les pilules furent cependant bien difficiles à avaler quand leur première fille épousa un musulman, leur seconde un juif et leur troisième un Chinois. Leurs espoirs de voir enfin l'une d'elles se marier à l'église se cristallisent donc sur la cadette, qui vient de rencontrer un bon catholique.", 'Comédie', 2014, 'https://image.tmdb.org/t/p/w500/bkAiSLxLJJEZXZZqgNna5BWcBIy.jpg'),
(98, "Le Diable s'habille en Prada", "Le Diable s'habille en Prada suit Andrea, jeune diplômée en journalisme, qui décroche un poste d'assistante chez une rédactrice en chef impitoyable d'un grand magazine de mode. Plongée dans un univers glamour mais exigeant, elle doit jongler entre ambitions professionnelles et vie personnelle.", 'Comédie', 2006, 'https://image.tmdb.org/t/p/w500/8912AsVuS7Sj915apArUFbv6F9L.jpg'),
(99, "Veuillez nous excuser pour la gêne occasionée", "Sébastien, contrôleur de train consciencieux et professionnel, rêve d'être muté dans le sud de la France. Pour valider sa mutation, il doit effectuer un dernier trajet de routine sous la supervision de Madeleine, une inspectrice qui ne va pas le lâcher. C'est là que tout déraille : entre un conducteur qui pense conduire un avion de chasse, un collègue très jaloux et des passagers tous plus dingues les uns que les autres, ce qui devait être une formalité va devenir le pire voyage de sa vie.", 'Comédie', 2023, 'https://image.tmdb.org/t/p/w500/oVJTN9Ur3dbFUi4pyxh8t8H02XE.jpg'),
(100, "Le Médecin Imaginaire", "Alex, alias DJ Wethu, est une star du monde de la nuit. Au bord du burn-out, il enchaîne les concerts aux quatre coins de la planète, jusqu'au jour où, en plein festival au Maroc, il fait une mauvaise chute et tombe de scène. Immobilisé sur place le temps de sa convalescence, il est placé sous la vigilance d'Abdel qui rêve de devenir aide-soignant. Le problème, c'est qu'il ne l'est pas tout à fait ! Une rencontre pour le moins inattendue...", 'Comédie', 2022, 'https://image.tmdb.org/t/p/w500/6XX6OAT9SfYhZTei3QHl6NyHuTc.jpg'),
(101, "Anora", "Anora de Sean Baker suit Ani, strip-teaseuse de Brooklyn qui croit toucher son rêve américain en épousant le fils d'un oligarque russe, avant que la réalité sociale et familiale ne vienne bouleverser ce conte de fées.", 'Comédie', 2024, 'https://image.tmdb.org/t/p/w500/cgXk2tNYhJZLXdBDO5DidAVzQ82.jpg'),
(102, "Do Revenge", "Si tu me venges… est une comédie noire adolescente où une ancienne star du lycée et une nouvelle élève concluent un pacte pour se venger chacune de leurs ennemis. Inspiré d'Hitchcock, le film mélange humour acide, intrigue de lycée et satire des codes sociaux...", 'Comédie', 2022, 'https://image.tmdb.org/t/p/w500/akIjKJDHcVN4bzifcEarKVPNpoa.jpg'),
(103, "Scary Movie", "Un soir, Drew Becker reçoit un appel anonyme d'un maniaque. Traquée dans sa maison, puis dans son jardin, elle finit par se faire tuer. Sa mort plonge ses camarades de lycée en plein cauchemar, d'autant qu'ils doivent désormais faire face à un tueur en série, caché parmi eux. Flairant le scoop, la journaliste Gail Hailstorn débarque en ville, bien décidée à harceler Cindy Campbell et ses amis à propos de cette histoire.", 'Comédie', 2000, 'https://image.tmdb.org/t/p/w500/reZ8NInXjMkkaOpUHcI3Pn7iaRN.jpg'),
(104, "Babysitting", "Babysitting est une comédie française déjantée où une garde d'enfant prévue comme tranquille tourne au chaos total. Franck, employé sérieux mais fêtard malgré lui, doit garder le fils de son patron le soir de ses 30 ans, quand ses amis s'invitent et transforment la nuit en délire filmé façon «found footage»", 'Comédie', 2014, 'https://image.tmdb.org/t/p/w500/t12bYhmv7LIcHT4TGGpW6WaMV2W.jpg'),
(105, "Austin Powers", "Austin Powers est une parodie délirante des films d'espionnage façon James Bond, où un agent secret britannique des années 60 est décongelé dans les années 90 pour affronter son ennemi juré, avec un style et des attitudes d'un autre temps...", 'Comédie', 1997, 'https://image.tmdb.org/t/p/w500/n8V61f1v7idya4WJzGEJNoIp9iL.jpg'),
(106, "Mon Voisin Totoro", "Dans les années 1950, Tatsuo Kusakabe, jeune anthropologue et professeur non titulaire d'une université de Tokyo, arrive dans le village où il va emménager avec ses deux filles, Satsuki, dix ans, et Mei, quatre ans. Les petites découvrent joyeusement leur nouvelle maison, qui n'a pas été habitée depuis un certain temps, et la campagne environnante où trône un camphrier gigantesque.", 'Animation', 1999, 'https://image.tmdb.org/t/p/w500/rtGDOeG9LzoerkDGZF9dnVeLppL.jpg'),
(107, "Là-Haut", "Carl Fredricksen, petit garçon, rêve d'être un explorateur depuis qu'il a vu aux actualités du cinéma les exploits de Charles Muntz, célèbre aventurier qui, à bord de son dirigeable et accompagné de ses chiens, a découvert les chutes du Paradis, un tepuy perdu dans la Guyane vénézuélienne.", 'Animation', 2009, 'https://image.tmdb.org/t/p/w500/pkO5YoznMR9neuHVzhxHK9JJpAj.jpg'),
(108, "Moi Moche et Méchant 1", "Dans un charmant quartier résidentiel délimité par des clôtures de bois blanc et orné de rosiers fleurissants se dresse une bâtisse noire entourée d'une pelouse en friche. Cette façade sinistre cache un secret : Gru, un méchant vilain, entouré d'une myriade de sous-fifres et armé jusqu'aux dents, qui, à l'insu du voisinage, complote le plus gros casse de tous les temps : voler la lune (Oui, la lune !).", 'Animation', 2010, 'https://image.tmdb.org/t/p/w500/placeholder.jpg'),
(109, "Tous en Scène !", "Buster Moon est un élégant koala, directeur d'une salle de théâtre dont les années de gloire passées commencent à tomber dans l'oubli. Buster est un éternel optimiste, et peut-être un peu fripouille. Il aime son théâtre plus que tout et fera le maximum pour le préserver. Une chance se présente à lui : organiser le plus grand concours de chant au monde. Cinq candidats se retrouvent en tête : une souris, un éléphant, un porc-épic, un cochon, et un gorille. Ils espèrent tous changer leur vie.", 'Animation', 2017, 'https://image.tmdb.org/t/p/w500/placeholder.jpg'),
(110, "Monstres et Cie", "À Monstropolis, la principale source d'énergie provient des cris des enfants. Monstres & Cie est la plus grande usine de traitement de cris de la ville. Grâce au nombre impressionnant de portes de placards dont dispose l'usine, une équipe de monstres pénètre dans le monde des humains pour terrifier durant la nuit les enfants et récolter leurs hurlements. Or, l'arrivée d'une enfant vient interrompre la compétition que se livrent deux monstres pour le titre de la créature la plus terrifiante.", 'Animation', 2002, 'https://image.tmdb.org/t/p/w500/wFSpyMsp7H0ttERbxY7Trlv8xry.jpg'),
(111, "La Belle au Bois Dormant", "L'histoire commence avec un roi et une reine qui, après de nombreuses années d'attente, ont enfin une fille. Pour célébrer sa naissance, ils organisent une grande fête et invitent toutes les fées du royaume, sauf une vieille fée qui n'a pas été invitée. Offensée par cet oubli, la vieille fée jette un sort à la princesse : elle se piquera le doigt sur un fuseau et tombera dans un sommeil profond pour cent ans.", 'Animation', 1959, 'https://image.tmdb.org/t/p/w500/d8cjpILAoYE3ucEs07Rxp2D96IZ.jpg'),
(112, "Dragons", "Hiccup est un adolescent viking de l'île de Berk, où se battre avec des dragons est un mode de vie. Ses idées progressistes et son sens de l'humour étrange le tiennent à part des autres, malgré le fait que son père est le chef du clan. Entraîné dans une école de combat de dragon, il essaie de prouver qu'il est un vrai viking. Mais quand il se lie d'amitié avec un dragon blessé qu'il nomme Kromou, il a la chance de tracer une nouvelle voie pour l'avenir de son peuple.", 'Animation', 2010, 'https://image.tmdb.org/t/p/w500/tm153lMrHy6HykEYwoP0EI3dQ8k.jpg'),
(113, "Shrek", "Il était une fois, dans un marais lointain, un ogre au nom de Shrek qui voit sa précieuse solitude brisée pas une invasion de personnages de contes de fées agaçants. Ils ont tous été bannis de leur royaume par le méchant Lord Farquaad. Décidé à sauver leurs maisons -- pour ne pas dire la sienne -- Shrek conclut un marché avec Farquad et décide de sauver la princesse Fiona pour qu'elle se marie avec ce dernier. Mais Shrek ne réalise pas que la princesse à un secret sombre et profond.", 'Animation', 2001, 'https://image.tmdb.org/t/p/w500/iB64vpL3dIObOtMZgX3RqdVdQDc.jpg'),
(114, "Zootopia", "Zootopia est une ville qui ne ressemble à aucune autre : seuls les animaux y habitent ! On y trouve des quartiers résidentiels élégants comme le très chic Sahara Square, et d'autres moins hospitaliers comme le glacial Tundratown. Dans cette incroyable métropole, chaque espèce animale cohabite avec les autres. Qu'on soit un immense éléphant ou une minuscule souris, tout le monde a sa place à Zootopia !", 'Animation', 2016, 'https://image.tmdb.org/t/p/w500/oJ7g2CifqpStmoYQyaLQgEU32qO.jpg'),
(115, "Ratatouille", "Rémy n'est pas un jeune rat comme les autres. Il a un véritable don, celui de cuisiner, marier les saveurs, découvrir de nouveaux arômes et un rêve : devenir un grand chef et le premier rat de goût. Il est prêt à tout pour vivre sa passion, notamment venir s'installer avec sa famille sous les cuisines d'un des plus grands restaurants parisiens : celui d'Auguste Gusteau, la star des fourneaux.", 'Animation', 2007, 'https://image.tmdb.org/t/p/w500/t3vaWRPSf6WjDSamIkKDs1iQWna.jpg'),
(116, "Vice-Versa", "Grandir n'est pas de tout repos, et la petite Riley ne fait pas exception à la règle. À cause du travail de son père, elle vient de quitter le Midwest et la vie qu'elle a toujours connue pour emménager avec sa famille à San Francisco. Riley est guidée par ses émotions - la Joie, la Peur, la Colère, le Dégoût, et la Tristesse. Ces émotions vivent au quartier Général, le centre de contrôle de l'esprit de Riley, et l'aident et la conseillent dans sa vie quotidienne.", 'Animation', 2015, 'https://image.tmdb.org/t/p/w500/iFTyxz6qvGAPNvZWwANuyvHz95H.jpg'),
(117, "Raiponce", "Lorsque Flynn Rider, le bandit le plus recherché du royaume, se réfugie dans une mystérieuse tour, il se retrouve pris en otage par Raiponce, une belle et téméraire jeune fille à l'impressionnante chevelure de 20 mètres de long, gardée prisonnière par Mère Gothel. L'étonnante geôlière de Flynn cherche un moyen de sortir de cette tour où elle est enfermée depuis des années. Elle passe alors un accord avec le séduisant brigand.", 'Animation', 2010, 'https://image.tmdb.org/t/p/w500/ym7Kst6a4uodryxqbGOxmewF235.jpg'),
(118, "Super Mario Bros", "Un plombier nommé Mario parcourt un labyrinthe souterrain avec son frère, Luigi, essayant de sauver une princesse capturée. Adaptation cinématographique du célèbre jeu vidéo.", 'Animation', 2023, 'https://image.tmdb.org/t/p/w500/qNBAXBIQlnOThrVvA6mA2B5ggV6.jpg'),
(119, "Les Indestructibles", "Dans un monde où les super-héros sont monnaie courante, l'un des plus célèbres d'entre eux, M. Indestructible, passe une journée ordinaire, stoppant des braqueurs en fuite, sauvant un chat coincé dans un arbre et gérant même (maladroitement) Buddy, un fan un peu trop impliqué, croisant au passage quelques collègues comme Elastigirl et Frozone...", 'Animation', 2004, 'https://image.tmdb.org/t/p/w500/2LqaLgk4Z226KkgPJuiOQ58wvrm.jpg'),
(120, "Toy Story", "Toy Story est le premier long-métrage d'animation 3D de Pixar et une révolution technique et artistique. Dans la chambre d'Andy, les jouets prennent vie et voient leur équilibre bouleversé par l'arrivée de Buzz l'Éclair, suscitant jalousies et aventures.", 'Animation', 1996, 'https://image.tmdb.org/t/p/w500/pxG26JdyuiDvJbSoucknaFiLeZD.jpg'),
(121, "A Miku who CAN'T SING", "Ichika est une lycéenne musicienne qui peut pénétrer dans un endroit mystérieux appelé « SEKAI », où elle et ses amis expriment leurs émotions les plus profondes à travers la musique avec Hatsune Miku. Un jour, après avoir donné un concert, Ichika rencontre une nouvelle Miku. Cette dernière a beau essayer de chanter, elle ne parvient pas à toucher le cœur de ses auditeurs...", 'Animation', 2025, 'https://image.tmdb.org/t/p/w500/uiQ6wj8TPYHueuIJRsNlPruzogT.jpg'),
(122, "Blanche Neige et les Septs Nains", "Un livre de contes intitulé Blanche-Neige et les Sept Nains s'ouvre et une voix entame la narration du conte. Il explique que Blanche-Neige est une princesse vivant auprès de sa vaniteuse et malveillante belle-mère, la Reine. Courroucée et jalouse de la beauté de Blanche-Neige, elle l'oblige à faire des tâches ménagères et à se vêtir de haillons..", 'Animation', 1938, 'https://image.tmdb.org/t/p/w500/MBiKqTsouYqAACLYNDadsjhhC0.jpg'),
(123, "La Belle et la Bête", "Belle, une jeune femme intelligente et passionnée de lecture, vit dans un village français où elle repousse les avances du vaniteux Gaston. Lorsque son père Maurice se perd dans la forêt et trouve refuge dans un mystérieux château, il est capturé par son maître : une Bête terrifiante, en réalité un prince victime d'une malédiction...", 'Animation', 1992, 'https://image.tmdb.org/t/p/w500/8bErT2koHXAUSW5PdLQqgL5gEEe.jpg'),
(124, "Batman contre le Fantôme Masqué", "Batman contre le Fantôme masqué suit le Chevalier noir, accusé à tort d'une série de meurtres visant des chefs de la pègre, tandis qu'une silhouette mystérieuse sème la terreur à Gotham. Entre enquête périlleuse et résurgences d'un passé amoureux, il doit démêler une affaire où secrets et justice s'entrechoquent..", 'Animation', 2009, 'https://image.tmdb.org/t/p/w500/hT4ehUteagUrhUOHAtmYiY7mp5l.jpg'),
(125, "Le Château Ambulant", "Sophie, une jeune modiste est l'aînée de trois sœurs, rencontre un magicien nommé Hauru alors qu'elle se rend chez sa sœur Lettie. En rentrant chez elle, elle rencontre la sorcière des Landes, qui la transforme en une femme de 90 ans. Cherchant à briser la malédiction, Sophie quitte la maison et part à travers la campagne.", 'Animation', 2004, 'https://image.tmdb.org/t/p/w500/13kOl2v0nD2OLbVSHnHk8GUFEhO.jpg'),
(126, "Your Name", "Mitsuha, adolescente coincée dans une famille traditionnelle, rêve de quitter ses montagnes natales pour découvrir la vie trépidante de Tokyo. Elle est loin d'imaginer pouvoir vivre l'aventure urbaine dans la peau de... Taki, un jeune lycéen vivant à Tokyo. À travers ses rêves, Mitsuha se voit littéralement propulsée dans la vie du jeune garçon. Quel mystère se cache derrière ces rêves étranges qui unissent deux destinées que tout oppose et qui ne se sont jamais rencontrées ?", 'Animation', 2016, 'https://image.tmdb.org/t/p/w500/q719jXXEzOoYaps6babgKnONONX.jpg'),
(127, "Les Mondes de Ralph", "Les Mondes de Ralph suit Ralph la Casse, méchant d'un jeu d'arcade rétro, bien décidé à prouver qu'il peut être un héros. Sa quête l'entraîne à travers divers univers vidéoludiques où il rencontre Vanellope, une pilote rejetée...", 'Animation', 2012, 'https://image.tmdb.org/t/p/w500/zWoIgZ7mgmPkaZjG0102BSKFIqQ.jpg'),
(128, "Le Voyage de Chihiro", "Au cours d'un voyage en voiture, la famille de Chihiro,10 ans, fait une halte dans un parc à thème qui semble abandonné. Ses parents découvrent des mets succulents dans un restaurant et commencent à manger. Ils se retrouvent alors transformés en cochons. Prise de panique, Chihiro s'enfuit et rencontre l'énigmatique Haku, qui lui explique le fonctionnement de l'univers dans lequel elle vient de pénétrer. Pour sauver ses parents, la fillette va devoir faire face à la terrible sorcière Yubaba.", 'Animation', 2002, 'https://image.tmdb.org/t/p/w500/39wmItIWsg5sZMyRUHLkWBcuVCM.jpg'),
(129, "A Silent Voice", "Nishimiya est une élève douce mais qui elle est harcelée par Ishida, car elle est sourde. Dénoncé, le garçon est à son tour rejeté par ses camarades. Des années plus tard, il apprend la langue des signes et part à la recherche de la jeune fille.", 'Animation', 2018, 'https://image.tmdb.org/t/p/w500/tuFaWiqX0TXoWu7DGNcmX3UW7sT.jpg'),
(130, "Le Comte de Monte Cristo", "Le film raconte l'histoire d'Edmond Dantès, trahi et emprisonné à tort, qui revient riche et puissant pour se venger de ses ennemis.", 'Historique', 2024, 'https://image.tmdb.org/t/p/w500/sAT1P3FGhtJ68anUyJScnMu8t1l.jpg'),
(131, "Le Pianiste", "Le film raconte l'histoire du pianiste polonais juif Władysław Szpilman, dit aussi Wladek. L'histoire se déroule à Varsovie en Pologne pendant la Seconde Guerre mondiale. W. Szpilman est alors le pianiste officiel de la Radio polonaise et une figure connue du milieu culturel polonais. Lorsque les nazis s'emparent de la ville, ils suppriment progressivement les droits des Juifs, puis les parquent dans le ghetto créé pour les regrouper en vue de leur extermination.", 'Historique', 2002, 'https://image.tmdb.org/t/p/w500/6UhMIZaaoe2HUU7sEIwYpuYgugh.jpg'),
(132, "Le Dictateur", "Lors de la Première Guerre mondiale, dans un pays imaginaire nommé Tomainia[b] et ressemblant beaucoup à l'Allemagne, un soldat maladroit sauve la vie d'un pilote de chasse nommé Schultz. Tous deux réussissent à s'enfuir en avion, mais l'appareil s'écrase et le soldat est blessé. Devenu amnésique, le soldat passe de longues années à l'hôpital, coupé du monde. Entre-temps, la Tomainia est devenue un régime dictatorial et fasciste dirigé par Adenoïd Hynkel (une caricature d'Adolf Hitler), où les Juifs sont persécutés comme sous le régime nazi.", 'Historique', 1940, 'https://image.tmdb.org/t/p/w500/bHLMOA9XP6Ak7IUhynlewEMAfIA.jpg'),
(133, "Oppenheimer", "En 1926, Robert Oppenheimer étudie au laboratoire Cavendish de Cambridge au Royaume-Uni. Outre son mal du pays, il est en proie à des crises d'anxiété, surtout parce qu'il ne se sent pas à l'aise dans les travaux pratiques ; il préfère la théorie. Il travaille sous la direction de l'exigeant Patrick Blackett et va même jusqu'à empoisonner la pomme de ce dernier.", 'Historique', 2023, 'https://image.tmdb.org/t/p/w500/8Gxv8gSFCU0XGDykEGv7zR1n2ua.jpg'),
(134, "Le Vent se lève", "Une nuit, un jeune garçon, Jirō Horikoshi, rêve qu'il pilote un prototype d'avion aux ailes d'oiseau ; son rêve se termine en cauchemar lorsqu'il est attaqué par un énorme bombardier. Jirō s'éveille et entame une journée ordinaire dans le Japon de 1918, où il grandit en compagnie de sa famille. Jirō est un jeune garçon travailleur, épris de justice et surtout passionné d'aéronautique.", 'Historique', 2013, 'https://image.tmdb.org/t/p/w500/yksyL50h9PdCX19tQD1aYCb9dbY.jpg'),
(135, "Ni chaînes, ni maîtres", "1759, sur l'Isle de France, actuelle Île Maurice. Massamba et Mati, esclaves dans la plantation d'Eugène Larcenet, vivent dans la peur et le labeur. Lui rêve que sa fille soit affranchie, elle de quitter l'enfer vert de la canne à sucre. Une nuit, elle s'enfuit. Madame La Victoire, célèbre chasseuse d'esclaves, est engagée pour la traquer. Massamba n'a d'autre choix que de s'évader à son tour. Par cet acte, il devient un «marron», un fugitif qui rompt à jamais avec l'ordre colonial.", 'Historique', 2024, 'https://image.tmdb.org/t/p/w500/dVJ91RJuPsdr9F0zIMskWcSNoHi.jpg'),
(136, "La Chute", "La Chute (2004) plonge au cœur des derniers jours d'Adolf Hitler, retranché dans son bunker à Berlin en avril 1945, alors que le IIIe Reich s'effondre. À travers le regard de sa secrétaire et de ses proches, le film d'Oliver Hirschbiegel peint un huis clos intense sur fond de déroute militaire et de tensions psychologiques.", 'Historique', 2004, 'https://image.tmdb.org/t/p/w500/g46xbQESDa91Jb7mSXZgzxJs5Y.jpg'),
(137, "La Ligne Rouge", "La Ligne rouge de Terrence Malick revisite la bataille de Guadalcanal en mêlant scènes de combat et méditation sur la nature, la vie et la mort. Loin d'être un simple film de guerre, il déploie une réflexion poétique, contemplative et philosophique sur l'humanité au cœur du chaos. Sa photographie somptueuse, sa bande originale envoûtante et son casting prestigieux en font une œuvre marquante et singulière, saluée comme un chef-d'œuvre du genre.", 'Historique', 1998, 'https://image.tmdb.org/t/p/w500/cBl99EjBIt8snykCx2RsdoH9wVs.jpg'),
(138, "Simone", "Simone, le voyage du siècle retrace le destin hors normes de Simone Veil, de son enfance marquée par la tragédie à ses combats politiques majeurs, dressant un portrait à la fois intime et épique d'une femme qui a profondément influencé son époque par son message humaniste.", 'Historique', 2022, 'https://image.tmdb.org/t/p/w500/kcoSySNTUfIPkMwxfQsDIIoQ7zm.jpg'),
(139, "Apollo 11", "Réalisé à partir d'images 70mm inédites récemment découvertes et plus de 11 000 heures d'enregistrements audio, Apollo 11 plonge au cœur de la plus célèbre mission de la NASA et des premiers pas de l'Homme sur la Lune. Ce film est un voyage en immersion aux côtés des astronautes et du centre de contrôle de la mission et permet de vivre au plus près les inoubliables journées de 1969 dont on célèbre cette année le 50ème anniversaire...", 'Historique', 2019, 'https://image.tmdb.org/t/p/w500/woLMRroHyoTGoXyxdEeBJEYBFtu.jpg'),
(140, "La Liste de Schindler", "La Liste de Schindler suit, durant la Seconde Guerre mondiale, la transformation d'Oskar Schindler, industriel allemand au départ intéressé par le profit, qui utilise sa position pour sauver plus d'un millier de Juifs de la déportation. Réalisé en noir et blanc par Steven Spielberg, ce film intense et sobre est salué pour sa force émotionnelle, sa précision historique et ses interprétations mémorables. Souvent considéré comme un chef-d'œuvre, il reste une œuvre incontournable du cinéma historique.", 'Historique', 1993, 'https://image.tmdb.org/t/p/w500/edtkWFaiRUIF55FCDstESaU1xm4.jpg'),
(141, "Parasite", "Le film suit la famille Kim, qui vit dans un sous-sol et lutte pour joindre les deux bouts. Un jour, le fils, Ki-woo, réussit à se faire recommander pour donner des cours particuliers d'anglais à la fille de la riche famille Park. Chaque membre de la famille Kim se fait passer pour un professionnel qualifié, sans lien de parenté, afin de s'assurer des emplois dans la maison des Park. Au fur et à mesure que les Kim s'installent dans leur nouvelle vie, les tensions entre les deux familles augmentent..", 'Thriller', 2019, 'https://image.tmdb.org/t/p/w500/7IiTTgloJzvGI1TAYymCfbfl3vT.jpg'),
(142, "Greta", "Greta de Neil Jordan est un thriller psychologique où une jeune femme solitaire à New York se lie d'amitié avec une veuve excentrique après lui avoir restitué un sac trouvé dans le métro. Ce qui commence comme une relation réconfortante prend peu à peu une tournure inquiétante au fur et à mesure que de sombres intentions se révèlent. Les critiques saluent surtout l'interprétation glaçante d'Isabelle Huppert, malgré quelques clichés et invraisemblances.", 'Thriller', 2018, 'https://image.tmdb.org/t/p/w500/9hBpFyJ3pGdupXbaC2L7nGvLMBn.jpg'),
(143, "Civil War", "Aux États-Unis, une guerre civile a éclaté entre le gouvernement devenu autoritaire et diverses factions régionales, menées par les États de Californie et du Texas, devenus sécessionnistes. À Washington, le président, qui effectue un troisième mandat, affirme à la télévision que la victoire est proche. Au même moment, à Brooklyn, la célèbre photographe de guerre Lee Smith sauve la photo-journaliste en herbe Jessie d'un attentat suicide visant des civils venus se réapprovisionner en eau.", 'Thriller', 2024, 'https://image.tmdb.org/t/p/w500/sh7Rg8Er3tFcN9BpKIPOMvALgZd.jpg'),
(144, "Bodies Bodies Bodies", "Bodies Bodies Bodies est une comédie horrifique satirique où un groupe de riches jeunes adultes se retrouve isolé dans un manoir pendant un ouragan. Un jeu innocemment lancé se transforme en cauchemar paranoïaque.", 'Thriller', 2023, 'https://image.tmdb.org/t/p/w500/hSuTjDmqRdy7Dii8ymnF2WILTeP.jpg'),
(145, "Black Swan", "Nina est parfaite pour danser le Cygne blanc, innocent et pur, au New York City ballet. Mais elle doit confronter son côté obscur, rusée et sensuelle...", 'Thriller', 2011, 'https://image.tmdb.org/t/p/w500/viWheBd44bouiLCHgNMvahLThqx.jpg'),
(146, "Les Marches du Pouvoir", "Stephen Meyers est le jeune, mais déjà très expérimenté conseiller de campagne du gouverneur Morris, qui se prépare pour les élections à la présidence américaine. Idéaliste et décidé à faire honnêtement tout ce qu'il peut pour faire gagner celui qu'il considère sincèrement comme le meilleur candidat, Stephen s'engage totalement.", 'Thriller', 2011, 'https://image.tmdb.org/t/p/w500/w8t4UnJnC24S9ygoaFgmMzRbErd.jpg'),
(147, "Le Monde après Nous", "Amanda et Clay louent une maison dans un coin reculé du Long Island pour y passer des vacances paisibles avec leurs deux enfants. Un soir, les propriétaires, Ruth et G. H., reviennent en urgence, affirmant qu'une coupure électrique a paralysé les alentours. Sans téléphone, télévision, ni internet, les locataires plongent dans l'incertitude. Peuvent-ils vraiment faire confiance à leurs hôtes ?", 'Thriller', 2023, 'https://image.tmdb.org/t/p/w500/aTbXAMKlCbWWXeFdZf66gBZGIh4.jpg'),
(148, "Kill Bill - Volume 1", "Kill Bill : Volume 1 suit la quête d'une ancienne tueuse à gages, laissée pour morte le jour de son mariage, qui se réveille d'un coma de quatre ans et poursuit sa vengeance contre ses anciens complices et leur chef, Bill..", 'Thriller', 2003, 'https://image.tmdb.org/t/p/w500/v7TaX8kXMXs5yFFGR41guUDNcnB.jpg'),
(149, "JOKER", "Dans les années 1980, à Gotham City, Arthur Fleck, un comédien de stand-up raté est agressé alors qu'il erre dans les rues de la ville déguisé en clown. Méprisé de tous et bafoué, il bascule peu à peu dans la folie pour devenir le Joker, un dangereux tueur psychotique...", 'Thriller', 2019, 'https://image.tmdb.org/t/p/w500/udDclJoHjfjb8Ekgsd4FDteOkCU.jpg'),
(150, "Seven", "Seven suit deux inspecteurs que tout oppose, Somerset, vétéran désabusé proche de la retraite, et Mills, jeune policier fougueux, dans leur traque d'un tueur en série orchestrant des meurtres inspirés des sept péchés capitaux. Réalisé par David Fincher, ce thriller psychologique se distingue par son atmosphère sombre, sa mise en scène immersive et l'excellence de ses interprètes. Considéré comme un classique du genre, il séduit par sa tension et son intensité jusqu'à la dernière scène.", 'Thriller', 1995, 'https://image.tmdb.org/t/p/w500/xIZ8huVdXCL7OMtsjd3XvmFP5sK.jpg'),
(151, "Fall", "Pour les meilleurs amis Becky et Hunter, la vie consiste à vaincre ses peurs et à repousser ses limites. Cependant, après avoir grimpé à 2 000 pieds au sommet d'une tour radio abandonnée et isolée, ils se retrouvent bloqués sans aucun moyen de descendre. Maintenant, leurs compétences d'escalade expertes sont mises à l'épreuve ultime alors qu'ils se battent désespérément pour survivre aux éléments, au manque de fournitures et aux hauteurs vertigineuses.", 'Thriller', 2022, 'https://image.tmdb.org/t/p/w500/spCAxD99U1A6jsiePFoqdEcY0dG.jpg'),
(152, "Le Silence des agneaux", "Le Silence des agneaux suit Clarice Starling, élève du FBI, lancée sur la piste d'un assassin qui dépouille ses victimes. Pour progresser, elle affronte derrière les barreaux l'esprit retors du Dr Hannibal Lecter, entamant avec lui un échange précis et troublant où se mêlent indices et confidences.", 'Thriller', 1991, 'https://image.tmdb.org/t/p/w500/eOOoZ43TMYnxIvLdeyZcBWuGyyn.jpg'),
(153, "Dans les Bois", "Dans les bois nous entraîne dans un lieu où les limites du temps ont disparu, dans une nature sauvage et d'une fragile beauté. Cette immersion totale dans ces forêts ancestrales est une expérience forte pour les spectateurs de tous âges. La caméra de Minaudas Survila a su capter et filmer les animaux de ces bois comme rarement.", 'Documentaire', 2017, 'https://image.tmdb.org/t/p/w500/pUUmy4SMmz8LO3F84Odj2BZdwS8.jpg'),
(154, "Terre des Ours", "Kamtchatka. Cette terre à l'état sauvage située en Extrême-Orient russe est le royaume des ours bruns. Au fil des saisons, chacun a ses préoccupations : la mère doit nourrir et protéger ses oursons qui veulent explorer le monde avec l'insouciance de leur jeunesse. Un ours tout juste sorti de l'enfance doit trouver sa place dans le monde adulte et gagner son autonomie. Enfin, le mâle doit constamment défendre son territoire et imposer sa force…", 'Documentaire', 2014, 'https://image.tmdb.org/t/p/w500/pQr542U7tsOLOgEi9H48PfWXvoC.jpg'),
(155, "Kaizen", "Une exploration profonde et inspirante de la transformation personnelle d'Inoxtag, qui se prépare à une aventure ambitieuse : l'ascension de l'Everest. Plus qu'une simple quête de gloire, ce projet met en lumière les défis physiques et éthiques majeurs que cela implique.", 'Documentaire', 2024, 'https://image.tmdb.org/t/p/w500/mbpZW0TOykpaEZwEIO5RR4ul3ca.jpg'),
(156, "Le Fondateur", "En 1954, Raymond Ray Kroc vend des machines à milk-shake dans le Missouri quand une commande importante l'emmène en Californie, à San Bernardino. Il y fait alors la rencontre des frères Richard 'Dick' et Maurice 'Mac' McDonald. Ils sont les propriétaires et concepteurs d'un restaurant de restauration rapide révolutionnaire : McDonald's. Ils en ont fait le contre-modèle absolu du drive-in : rapide, efficace, peu coûteux, familial.", 'Documentaire', 2016, 'https://image.tmdb.org/t/p/w500/8gLIksu5ggdfBL1UbeTeonHquxl.jpg'),
(157, "Félins", "En Afrique, au Kenya, dans l'une des régions les plus sauvages du monde, les animaux vivent libres et loin des hommes. Au sud du fleuve qui divise ces magnifiques terres, règne le clan des lions mené par Fang. La lionne Layla y élève la jeune Mara. Entre chasse et liens familiaux puissants, c'est la vie d'une famille qui s'écrit. Au nord du fleuve, le lion Kali et ses quatre fils rêvent d'étendre leur territoire. Bientôt, les eaux seront assez basses pour que les maîtres du nord tentent leur chance au sud…", 'Documentaire', 2025, 'https://image.tmdb.org/t/p/w500/As22MQ8G3ILsdzsSIv1u9qEz6hE.jpg'),
(158, "Resistance", "Strasbourg, 1938. Alors que Marcel Mangel rêve de faire une carrière de mime, il décide de prendre en charge, en compagnie de boy-scouts, cent vingt-trois orphelins juifs rescapés de l'Allemagne nazie. Lorsque la France est envahie, le groupe gagne le sud du pays afin de placer les enfants dans des familles d'accueil, et Marcel Mangel, devenu Marceau, intègre la Résistance.", 'Documentaire', 2022, 'https://image.tmdb.org/t/p/w500/placeholder.jpg'),
(159, "La Planète des Poules", "Les poules et les hommes, une histoire d'amour qui dure depuis 5 000 ans. Comment une gallinacée forestière sans prétention a-t-elle réussi à conquérir les cinq continents ? Les poules sont aujourd'hui plus de 19 milliards sur Terre et sont bien plus nombreuses que n'importe quelle autre espèce d'oiseau sauvage.", 'Documentaire', 2014, 'https://image.tmdb.org/t/p/w500/a5P4AG2jelryQAtRUsGQplx0AGm.jpg'),
(160, "Sur le Chemin de l'école", "Jackson, Zahira, Samuel et Carlos, quatre enfants, vivent l'un au Kenya, l'autre au Maroc, les autres enfin en Inde et en Patagonie. Tous les quatre, même s'ils ne se connaissent pas, sont prêts à relever tous les défis pour aller à l'école, espérant que l'éducation leur permettra d'échapper à leur destinée. Ainsi Zahira qui, chaque semaine, emprunte un chemin long, sinueux et dangereux pour quitter les monts de l'Atlas où vivent ses parents et rejoindre l'école.", 'Documentaire', 2013, 'https://image.tmdb.org/t/p/w500/placeholder.jpg');
